class TokenBucket:
    def __init__(self, rate):
        self.tokens = rate
    def allow(self):
        if self.tokens > 0:
            self.tokens -= 1
            return True
        return False
tb = TokenBucket(2)
print(sum(1 for _ in range(3) if tb.allow()))
print("ok", True)
print("rate", 2)
